args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT ?team ?teamLabel WHERE {
  wd:Q11576 p:P54 ?membership.
  ?membership ps:P54 ?team;
                pq:P580 ?start;
                pq:P582 ?end.
  FILTER(YEAR(?start) <= 2002 && YEAR(?end) >= 2002)
  FILTER(LANG(?teamLabel) = "en")
  OPTIONAL { ?team rdfs:label ?teamLabel }
}

SELECT ?team ?teamLabel WHERE {
  wd:Q11576 p:P54 ?membership.
  ?membership ps:P54 ?team;
                pq:P580 ?start;
                pq:P582 ?end.
  FILTER(YEAR(?start) <= 2002 && YEAR(?end) >= 2002)
  FILTER(CONTAINS(STR(?team), "Q"))
  OPTIONAL { ?team rdfs:label ?teamLabel FILTER(LANG(?teamLabel) = "en") }
  FILTER(CONTAINS(?teamLabel, "Club") || CONTAINS(?teamLabel, "Real Madrid"))
}
